            // carácter
            for (int caracter = 1; caracter <= (2 * altura) - 1; caracter++) {
                System.out.print(c + " ");
            }
            System.out.println();
        }
        // parte inferior
        filas--; // eliminamos la fila superior
        for (int altura = 1; altura <= filas; altura++) {
            // espacios
            for (int espacios = 1; espacios <= altura; espacios++) {
                System.out.print("  ");
