    {
        return n*n*n;
    }

    static int mult(int a, int b)
    {
        return a*b;
    }

    static void tablaMult(int num)
    {
        System.out.println("\nTABLA DE MULTIPLICAR DEL "+num);
        for (int i = 1; i <= 10; i++) {
