        paginas = new Pagina[365];
        int contadorMes = 1;
        int contadorDia = 1;
        for (int i = 0; i < this.paginas.length; i++) {
            paginas[i] = new Pagina(contadorDia++, contadorMes);
            if (contadorDia > diasMes[contadorMes - 1]) {
                contadorDia = 1;
                contadorMes++;
            }
        }
        this.abierta = this.paginas[0];
    }

