        }

        // se retira y se registra
        saldo -= cantidad;
        movimientos.add(new Movimiento(LocalDateTime.now(), cantidad, Movimiento.RETIRO));
        System.out.println("Se han retirado correctamente " + cantidad + "€ de la cuenta " + numeroCuenta);
