                hayPalabras = false;
                for (List<String> palabrasArchivo : palabrasArchivos) {
                    if (!palabrasArchivo.isEmpty()) {
                        escritorBuffer.write(palabrasArchivo.remove(0) + " ");
                        hayPalabras = true;
                    }
                }
            }
        }
    }

